import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set',
    parameters: {
      assignments: {
        assignments: [
          {
            id: '1',
            name: 'message',
            value: 'Hello from artifact click test',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('artifact-click-test', 'artifact click test')
  .add(manualTrigger)
  .to(setNode);
